// hooks/useRoutes.ts
import { useEffect, useState } from 'react'
import { supabase } from '../lib/supabase'
import { Route, UserCreatedRoute } from '../types'
import { toast } from 'react-hot-toast'

export function useRoutes() {
  const [routes, setRoutes] = useState<Route[]>([])
  const [userRoutes, setUserRoutes] = useState<UserCreatedRoute[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const fetchRoutes = async () => {
    try {
      setLoading(true)
      setError(null)
      
      const [routesRes, userRoutesRes] = await Promise.all([
        supabase
          .from('routes')
          .select(`
            *,
            stops:route_stops(
              *,
              stop:stops(*)
            )
          `)
          .order('created_at', { ascending: false }),
        
        supabase
          .from('user_created_routes')
          .select(`
            *,
            user:users(*),
            main_route:routes(*)
          `)
          .order('created_at', { ascending: false })
      ])

      if (routesRes.error) throw routesRes.error
      if (userRoutesRes.error) throw userRoutesRes.error
      
      setRoutes(routesRes.data || [])
      setUserRoutes(userRoutesRes.data || [])
    } catch (err: any) {
      setError(err.message)
      toast.error('Failed to fetch routes')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchRoutes()
    
    // Setup real-time subscriptions
    const routesSubscription = supabase
      .channel('routes-channel')
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'routes' },
        fetchRoutes
      )
      .subscribe()

    const userRoutesSubscription = supabase
      .channel('user-routes-channel')
      .on('postgres_changes', 
        { event: '*', schema: 'public', table: 'user_created_routes' },
        fetchRoutes
      )
      .subscribe()

    return () => {
      routesSubscription.unsubscribe()
      userRoutesSubscription.unsubscribe()
    }
  }, [])

  const approveRoute = async (routeId: string) => {
    try {
      const { error } = await supabase
        .from('routes')
        .update({ approved: true })
        .eq('id', routeId)

      if (error) throw error
      
      toast.success('Route approved successfully')
      fetchRoutes()
    } catch (err: any) {
      toast.error('Failed to approve route')
    }
  }

  const rejectRoute = async (routeId: string, reason: string) => {
    try {
      const { error } = await supabase
        .from('routes')
        .update({ 
          approved: false,
          rejection_reason: reason
        })
        .eq('id', routeId)

      if (error) throw error
      
      toast.success('Route rejected')
      fetchRoutes()
    } catch (err: any) {
      toast.error('Failed to reject route')
    }
  }

  const deleteRoute = async (routeId: string) => {
    try {
      const { error } = await supabase
        .from('routes')
        .delete()
        .eq('id', routeId)

      if (error) throw error
      
      toast.success('Route deleted')
      fetchRoutes()
    } catch (err: any) {
      toast.error('Failed to delete route')
    }
  }

  return {
    routes,
    userRoutes,
    loading,
    error,
    refresh: fetchRoutes,
    approveRoute,
    rejectRoute,
    deleteRoute
  }
}