// app/dashboard/page.tsx
'use client'

import { useDashboardStats } from '../hooks/useDashboardStats'
import { useRoutes } from '../hooks/useRoutes'
import { StatsCards } from '../components/dashboard/StatsCards'
import { RecentActivity } from '../components/dashboard/RecentActivity'
import { Loader } from '../components/common/Loader'

export default function DashboardPage() {
  const { stats, loading: statsLoading } = useDashboardStats()
  const { routes, loading: routesLoading } = useRoutes()

  const pendingRoutes = routes.filter(route => !route.approved)

  if (statsLoading || routesLoading) {
    return <Loader message="Loading dashboard..." />
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-text">Dashboard Overview</h1>
        <p className="text-text-light">Welcome to Ghana Trotro Transit Admin</p>
      </div>

      <StatsCards stats={stats} />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-background rounded-lg shadow p-6">
          <h2 className="text-xl font-semibold text-text mb-4">Recent Users Activity</h2>
          <div className="space-y-3">
            <div className="p-3 bg-blue-50 rounded-lg">
              <p className="text-sm text-text-light">Active users today</p>
              <p className="text-2xl font-bold text-text">{stats.activeUsers}</p>
            </div>
            <div className="p-3 bg-green-50 rounded-lg">
              <p className="text-sm text-text-light">Searches today</p>
              <p className="text-2xl font-bold text-text">{stats.todaySearches}</p>
            </div>
            <div className="p-3 bg-purple-50 rounded-lg">
              <p className="text-sm text-text-light">Notifications sent</p>
              <p className="text-2xl font-bold text-text">{stats.notificationsSent}</p>
            </div>
          </div>
        </div>

        <div className="bg-background rounded-lg shadow p-6">
          <h2 className="text-xl font-semibold text-text mb-4">Routes Pending Approval</h2>
          <RecentActivity routes={pendingRoutes.slice(0, 5)} />
          {pendingRoutes.length === 0 && (
            <p className="text-text-light text-center py-4">No routes pending approval</p>
          )}
        </div>
      </div>

      <div className="bg-background rounded-lg shadow p-6">
        <h2 className="text-xl font-semibold text-text mb-4">Quick Actions</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <button className="p-4 bg-primary text-white rounded-lg hover:bg-primary-dark transition-colors">
            Send Notification
          </button>
          <button className="p-4 bg-success text-white rounded-lg hover:bg-success/90 transition-colors">
            Add New Stop
          </button>
          <button className="p-4 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors">
            View Reports
          </button>
          <button className="p-4 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors">
            System Settings
          </button>
        </div>
      </div>
    </div>
  )
}